<div class="modal" id="authModal"> <div class="modal-overlay" onclick="closeAuthModal()"></div> <div class="modal-content"> <div class="modal-header"><h2 class="modal-title" id="modalTitle">Entrar</h2></div> <form onsubmit="handleAuth(event); return false;"> <div class="form-group" id="nameField" style="display: none;"><label class="form-label">Nome</label><input type="text" class="form-input" id="authName" placeholder="O seu nome"></div> <div class="form-group"><label class="form-label">Email</label><input type="email" class="form-input" id="authEmail" placeholder="email@exemplo.com" required></div> <div class="form-group"><label class="form-label">Palavra-passe</label><input type="password" class="form-input" id="authPassword" placeholder="••••••••" required></div> <div class="form-group" id="confirmField" style="display: none;"><label class="form-label">Confirmar</label><input type="password" class="form-input" id="authConfirm" placeholder="••••••••"></div> <button type="submit" class="btn btn-primary w-full" id="authSubmit">Entrar</button> </form> <div class="modal-footer"><span id="modalSwitchText">Não tem conta?</span> <a href="#" class="modal-link" id="modalSwitchLink" onclick="switchAuthMode(); return false;">Criar conta</a></div> </div> </div>
<div class="modal" id="gameDetailModal"> <div class="modal-overlay" onclick="closeGameModal()"></div> <div class="modal-content modal-xl" id="gameDetailContent"></div> </div>
<div class="modal" id="profileEditModal"> <div class="modal-overlay" onclick="closeProfileEditModal()"></div> <div class="modal-content"> <div class="modal-header"><h2 class="modal-title">Editar Perfil</h2><div class="modal-close" onclick="closeProfileEditModal()">✕</div></div> <div class="form-group"><label class="form-label">Nome</label><input type="text" class="form-input" id="profileName" placeholder="Nome"></div> <div class="form-group"><label class="form-label">Avatar (URL)</label><input type="text" class="form-input" id="profileAvatar" placeholder="https://..."></div> <div class="form-group"><label class="form-label">Bio</label><textarea class="form-input" id="profileBio" rows="3" placeholder="Conte-nos sobre si..."></textarea></div> <button class="btn btn-primary w-full" onclick="saveProfile()">Guardar</button> </div> </div>
<div class="modal" id="emulatorModal"> <div class="modal-overlay" onclick="closeEmulatorModal()"></div> <div class="modal-content modal-xl" style="padding: 0; overflow: hidden;"> <div id="emulatorContainer" style="background: #000; aspect-ratio: 16/9; display: flex; align-items: center; justify-content: center; color: white;"> <div style="text-align: center;"> <div style="font-size: 4rem; margin-bottom: 1rem;">🎮</div> <h2 style="color: white;">Emulador WebAssembly</h2> <p id="emulatorGameName">A iniciar...</p> <div class="emulator-controls" style="justify-content: center; margin-top: 2rem;"> <button class="emu-btn" onclick="togglePause()">⏸️ Pausar</button> <button class="emu-btn" onclick="saveState()">💾 Save State</button> <button class="emu-btn" onclick="loadState()">📂 Load State</button> <button class="emu-btn" onclick="openCheatMenu()">🔍 Cheats</button> <button class="emu-btn" onclick="closeEmulatorModal()">✕ Fechar</button> </div> </div> </div> </div> </div>
